diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..a5d14b27c363 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -2921,6 +2921,37 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
   if (Instruction *R = foldSelectOfBools(SI))
     return R;

+  // Fold select (select A, B, false), C, (select A, D, E)
+  // into select A, (select B, C, D), E
+  // This simplifies nested selects with a common condition.
+  Value *A, *B, *D, *E;
+  SelectInst *CondSel, *FalseSel;
+  if (match(CondVal, m_Select(m_Value(A), m_Value(B), m_Zero())) &&
+      match(FalseVal, m_Select(m_Specific(A), m_Value(D), m_Value(E)))) {
+    CondSel = cast<SelectInst>(CondVal);
+    FalseSel = cast<SelectInst>(FalseVal);
+    // Only fold if the inner selects don't have extra uses.
+    if (CondSel->hasOneUse() && FalseSel->hasOneUse()) {
+      Value *NewSel = Builder.CreateSelect(B, TrueVal, D);
+      return SelectInst::Create(A, NewSel, E);
+    }
+  }
+
+  // Fold select (select A, true, B), (select A, D, E), F
+  // into select A, D, (select B, E, F)
+  // This is the "or" variant of the above pattern.
+  SelectInst *TrueSel;
+  if (match(CondVal, m_Select(m_Value(A), m_One(), m_Value(B))) &&
+      match(TrueVal, m_Select(m_Specific(A), m_Value(D), m_Value(E)))) {
+    CondSel = cast<SelectInst>(CondVal);
+    TrueSel = cast<SelectInst>(TrueVal);
+    // Only fold if the inner selects don't have extra uses.
+    if (CondSel->hasOneUse() && TrueSel->hasOneUse()) {
+      Value *NewSel = Builder.CreateSelect(B, E, FalseVal);
+      return SelectInst::Create(A, D, NewSel);
+    }
+  }
+
   // Selecting between two integer or vector splat integer constants?
   //
   // Note that we don't handle a scalar select of vectors:
@@ -3145,7 +3176,22 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         Value *Or = Builder.CreateLogicalOr(CondVal, FalseSI->getCondition());
         replaceOperand(SI, 0, Or);
         replaceOperand(SI, 2, FalseSI->getFalseValue());
-        return &SI;
+      }
+    }
+  }
+
+  // select (select C, C2, false), X, (select C, Y, Z) -> select C, (select C2, X, Y), Z
+  if (auto *CondSI = dyn_cast<SelectInst>(CondVal)) {
+    if (CondSI->getCondition()->getType() == CondVal->getType()) {
+      if (auto *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
+        if (FalseSI->getCondition() == CondSI->getCondition() &&
+            match(CondSI->getFalseValue(), m_Zero()) &&
+            CondSI->hasOneUse() && FalseSI->hasOneUse()) {
+          Value *NewSel = Builder.CreateSelect(CondSI->getTrueValue(), TrueVal,
+                                               FalseSI->getTrueValue());
+          return SelectInst::Create(CondSI->getCondition(), NewSel,
+                                    FalseSI->getFalseValue());
+        }
       }
     }
   }

